		@Setup(Level.Trial)
		public void setup() throws IOException {
			theme = Theme.valueOf(themeName);
			query = ThemeQueryCatalog.queryFor(theme, z_queryIndex);
			expectedRows = ThemeQueryCatalog.expectedCountFor(theme, z_queryIndex);
			expectedCountBindingValue = ThemeQueryCatalog.expectedCountBindingValueFor(theme, z_queryIndex);

			File storeDirectory = storeDirectory();
			if (!storeDirectory.exists() && !storeDirectory.mkdirs()) {
				throw new IOException("Unable to create fixed LMDB benchmark directory: " + storeDirectory);
			}

			storeConfig = createStoreConfig();
			store = new LmdbStore(storeDirectory, storeConfig);
			repository = new SailRepository(store);
			ensureDataLoadedAndValidated();
			waitForSketchesIfEnabled();
			connection = repository.getConnection();
		}

		@TearDown(Level.Trial)
		public void tearDown() {
			if (connection != null) {
				connection.close();
				connection = null;
			}
			if (repository != null) {
				repository.shutDown();
				repository = null;
			}
			store = null;
			storeConfig = null;
		}

		private void ensureDataLoadedAndValidated() throws IOException {
			DbFileSizes expectedDbFileSizes = readExpectedDbFileSizes();
			if (!hasExpectedDbFileSizes(expectedDbFileSizes)) {
				rebuildStoreFromScratch();
				expectedDbFileSizes = currentDbFileSizes();
				writeExpectedDbFileSizes(expectedDbFileSizes);
			}

			if (!hasExpectedDbFileSizes(expectedDbFileSizes)) {
				DbFileSizes currentDbFileSizes = currentDbFileSizes();
				throw new IllegalStateException("Unexpected LMDB db file sizes in fixed benchmark store. Expected "
						+ TRIPLES_DATA_FILE + "=" + expectedDbFileSizes.triplesDataSizeBytes + " and "
						+ VALUES_DATA_FILE + "=" + expectedDbFileSizes.valuesDataSizeBytes + " but got "
						+ TRIPLES_DATA_FILE + "=" + currentDbFileSizes.triplesDataSizeBytes + " and "
						+ VALUES_DATA_FILE + "=" + currentDbFileSizes.valuesDataSizeBytes);
			}

			if (!expectedDbFileSizeFile().isFile()) {
				writeExpectedDbFileSizes(expectedDbFileSizes);
			}
		}

		private void waitForSketchesIfEnabled() throws IOException {
			if (!sketchEstimatorEnabled) {
				return;
			}
			if (!Boolean.parseBoolean(System.getProperty(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_PROPERTY, "true"))) {
				return;
			}
			repository.init();
			long timeoutSeconds = Long.getLong(ThemeQueryBenchmark.WAIT_FOR_SKETCHES_TIMEOUT_SECONDS_PROPERTY,
					300L);
			BenchmarkJoinEstimatorSupport.awaitEstimatorReady(store, "theme plan/run benchmark setup", timeoutSeconds,
					TimeUnit.SECONDS);
		}

		private void rebuildStoreFromScratch() throws IOException {
			File storeDirectory = storeDirectory();
			if (repository != null) {
				repository.shutDown();
			}

			FileUtils.deleteDirectory(storeDirectory);
			if (!storeDirectory.exists() && !storeDirectory.mkdirs()) {
				throw new IOException("Unable to recreate fixed LMDB benchmark directory: " + storeDirectory);
			}

			storeConfig = createStoreConfig();
			storeConfig.setIterationCacheSyncThreshold(0);
			store = new LmdbStore(storeDirectory, storeConfig);
			repository = new SailRepository(store);
			loadData();

			repository.shutDown();
			repository = null;
			store = null;

			System.gc();

			store = new LmdbStore(storeDirectory, storeConfig);
			repository = new SailRepository(store);
		}

		private LmdbStoreConfig createStoreConfig() {
			LmdbStoreConfig config = ConfigUtil.createConfig();
			config.setSketchEstimatorEnabled(sketchEstimatorEnabled);
			return config;
		}

		private DbFileSizes readExpectedDbFileSizes() throws IOException {
			File file = expectedDbFileSizeFile();
			if (!file.isFile()) {
				return missingExpectedDbFileSizes();
			}
			Properties properties = new Properties();
			try (FileInputStream inputStream = new FileInputStream(file)) {
				properties.load(inputStream);
			}
			try {
				String tripleIndexes = properties.getProperty(TRIPLE_INDEXES_PROPERTY);
				if (!storeConfig.getTripleIndexes().equals(tripleIndexes)) {
					return missingExpectedDbFileSizes();
				}
				return new DbFileSizes(
						parseSizeProperty(properties, TRIPLES_DATA_SIZE_PROPERTY),
						parseSizeProperty(properties, VALUES_DATA_SIZE_PROPERTY));
			} catch (IllegalStateException e) {
				System.out.println("Ignoring invalid expected LMDB size file " + file + ": " + e.getMessage());
				if (!file.delete()) {
					System.out.println("Unable to delete invalid expected LMDB size file: " + file);
				}
				return missingExpectedDbFileSizes();
			}
		}

		private void writeExpectedDbFileSizes(DbFileSizes expectedDbFileSizes) throws IOException {
			Properties properties = new Properties();
			properties.setProperty(TRIPLES_DATA_SIZE_PROPERTY, Long.toString(expectedDbFileSizes.triplesDataSizeBytes));
			properties.setProperty(VALUES_DATA_SIZE_PROPERTY, Long.toString(expectedDbFileSizes.valuesDataSizeBytes));
			properties.setProperty(TRIPLE_INDEXES_PROPERTY, storeConfig.getTripleIndexes());
			try (FileOutputStream outputStream = new FileOutputStream(expectedDbFileSizeFile())) {
				properties.store(outputStream, "Expected LMDB data file sizes for ThemeQueryPlanRunBenchmark");
			}
		}

		private long parseSizeProperty(Properties properties, String propertyName) {
			String value = properties.getProperty(propertyName);
			if (value == null) {
				throw new IllegalStateException("Missing property " + propertyName);
			}
			try {
				return Long.parseLong(value);
			} catch (NumberFormatException e) {
				throw new IllegalStateException("Invalid long value for property " + propertyName + ": " + value, e);
			}
		}

		private DbFileSizes missingExpectedDbFileSizes() {
			return new DbFileSizes(-1L, -1L);
		}

		private DbFileSizes currentDbFileSizes() {
			return new DbFileSizes(dbFileSize(TRIPLES_DATA_FILE), dbFileSize(VALUES_DATA_FILE));
		}

		private boolean hasExpectedDbFileSizes(DbFileSizes expectedDbFileSizes) {
			DbFileSizes currentDbFileSizes = currentDbFileSizes();
			return currentDbFileSizes.triplesDataSizeBytes == expectedDbFileSizes.triplesDataSizeBytes
					&& currentDbFileSizes.valuesDataSizeBytes == expectedDbFileSizes.valuesDataSizeBytes;
		}

		private File expectedDbFileSizeFile() {
			return new File(storeDirectory(), EXPECTED_DB_FILE_SIZES_FILE);
		}

		private long dbFileSize(String relativePath) {
			return new File(storeDirectory(), relativePath).length();
		}

		private void loadData() throws IOException {
			StopWatch started = StopWatch.createStarted();
			try (SailRepositoryConnection loadConnection = repository.getConnection()) {
				RDFInserter inserter = new RDFInserter(loadConnection);
				for (Theme themeDataset : Theme.values()) {
					loadConnection.begin(IsolationLevels.NONE);
					System.out.println("Loading theme dataset: " + themeDataset);
					ThemeDataSetGenerator.generate(themeDataset, inserter);
					loadConnection.commit();
				}
			}
			started.stop();
			System.out.println("Loaded theme datasets in " + started);
		}

		private File storeDirectory() {
			return new File(STORE_DIRECTORY, "complete");
		}

		protected LmdbBenchmarkQueryPlan preparePlan() {
			return LmdbBenchmarkQueryPlan.prepare(store, connection, query);
		}

		protected QueryResultSummary evaluate(LmdbBenchmarkQueryPlan plan) {
			long rowCount = 0L;
			Long countBindingValue = null;
			try (CloseableIteration<BindingSet> result = plan.evaluate()) {
				while (result.hasNext()) {
					BindingSet bindings = result.next();
					rowCount++;
					if (expectedCountBindingValue.isPresent()) {
						if (rowCount > 1) {
							throw new IllegalStateException("Expected exactly one count row for "
									+ queryDescription() + " but saw at least " + rowCount + " rows");
						}
						countBindingValue = countBindingValue(bindings);
					}
				}
			}
			return new QueryResultSummary(rowCount, countBindingValue);
		}

		private Long countBindingValue(BindingSet bindings) {
			var value = bindings.getValue(COUNT_BINDING_NAME);
			if (value == null) {
				return null;
			}
			if (value instanceof Literal literal) {
				return literal.longValue();
			}
			throw new IllegalStateException("Unexpected aggregate binding type for " + COUNT_BINDING_NAME + ": "
					+ value);
		}

		protected void assertExpectedResult(QueryResultSummary result) {
			if (result.rowCount != expectedRows) {
				throw new IllegalStateException("Unexpected result row count for " + queryDescription() + ": expected "
						+ expectedRows + " but got " + result.rowCount);
			}
			if (expectedCountBindingValue.isPresent()) {
				if (result.countBindingValue == null) {
					throw new IllegalStateException("Expected literal ?" + COUNT_BINDING_NAME + " binding for "
							+ queryDescription() + " but got null");
				}
				long expectedValue = expectedCountBindingValue.getAsLong();
				if (result.countBindingValue != expectedValue) {
					throw new IllegalStateException("Unexpected ?" + COUNT_BINDING_NAME + " binding for "
							+ queryDescription() + ": expected " + expectedValue + " but got "
							+ result.countBindingValue);
				}
			}
		}

		protected long benchmarkResult(QueryResultSummary result) {
			return expectedCountBindingValue.isPresent() ? result.countBindingValue : result.rowCount;
		}

		private String queryDescription() {
			return themeName + " query " + z_queryIndex + " ("
					+ ThemeQueryCatalog.benchmarkQueryFor(theme, z_queryIndex).getName() + ")";
		}
